/* ════════════════════════════════════════════════════════════════
   Aura Decore — Premium Motion & Interactivity Layer
   THEO + LUNA · Aura Decore 2026
   Colar em: Online Store → Themes → Edit code → assets/aura-animations.css
   ════════════════════════════════════════════════════════════════ */

/* ─── Custom Cursor ──────────────────────────────────────────── */
* { cursor: none !important; }

.aura-cursor {
  position: fixed;
  top: 0; left: 0;
  width: 10px; height: 10px;
  background: rgba(180, 155, 120, 0.9);
  border-radius: 50%;
  pointer-events: none;
  z-index: 99999;
  transform: translate(-50%, -50%);
  transition: width 0.2s ease, height 0.2s ease, opacity 0.2s ease, background 0.2s ease;
  mix-blend-mode: multiply;
}

.aura-cursor-ring {
  position: fixed;
  top: 0; left: 0;
  width: 36px; height: 36px;
  border: 1.5px solid rgba(180, 155, 120, 0.35);
  border-radius: 50%;
  pointer-events: none;
  z-index: 99998;
  transform: translate(-50%, -50%);
  transition: width 0.35s ease, height 0.35s ease, border-color 0.35s ease;
  will-change: transform;
}

.aura-cursor--hover .aura-cursor { width: 18px; height: 18px; opacity: 0.7; }
.aura-cursor-ring--hover { width: 56px; height: 56px; border-color: rgba(180, 155, 120, 0.55); }
.aura-cursor--click .aura-cursor { width: 6px; height: 6px; }

/* ─── Header ─────────────────────────────────────────────────── */
.header-wrapper,
.site-header,
header[role="banner"] {
  transition:
    padding 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94),
    box-shadow 0.45s ease,
    backdrop-filter 0.45s ease,
    background-color 0.45s ease;
  will-change: padding, box-shadow;
}

.header--scrolled {
  padding-top: 8px !important;
  padding-bottom: 8px !important;
  backdrop-filter: blur(18px) saturate(1.4) !important;
  -webkit-backdrop-filter: blur(18px) saturate(1.4) !important;
  background-color: rgba(255, 252, 248, 0.88) !important;
  box-shadow: 0 2px 32px rgba(100, 80, 50, 0.08) !important;
}

/* Logo hover */
.header__heading-logo,
.header__heading a img,
.site-header__logo img {
  transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1), filter 0.4s ease;
  will-change: transform, filter;
}
.header__heading-logo:hover,
.header__heading a:hover img,
.site-header__logo a:hover img {
  transform: scale(1.06);
  filter: drop-shadow(0 4px 20px rgba(180, 155, 120, 0.5));
}

/* Nav links underline */
.header__menu-item a,
.header__active-menu-item,
.list-menu__item a {
  position: relative;
  text-decoration: none !important;
  transition: color 0.3s ease;
}
.header__menu-item a::after,
.list-menu__item a::after {
  content: '';
  position: absolute;
  bottom: -2px; left: 50%;
  width: 0; height: 1.5px;
  background: linear-gradient(90deg, transparent, rgba(180,155,120,1), transparent);
  transition: width 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94), left 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  border-radius: 2px;
}
.header__menu-item a:hover::after,
.list-menu__item a:hover::after {
  width: 100%;
  left: 0;
}

/* Header icons */
.header__icon svg,
.header__icon,
.cart-count-bubble,
.header__icon-wrapper {
  transition: transform 0.35s cubic-bezier(0.34, 1.56, 0.64, 1), filter 0.35s ease;
}
.header__icon:hover svg,
.header__icon:hover {
  transform: scale(1.18) rotate(-4deg);
  filter: drop-shadow(0 2px 12px rgba(180,155,120,0.55));
}

/* ─── Hero Banner ────────────────────────────────────────────── */
.hero-parallax-wrapper {
  position: relative;
  overflow: hidden;
}

.hero-parallax-bg {
  will-change: transform;
  transform-origin: center center;
}

.hero-parallax-layer {
  will-change: transform;
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
}

/* Hero text stagger — initial hidden state */
.hero-stagger-item {
  opacity: 0;
  transform: translateY(28px);
  will-change: opacity, transform;
}

/* Hero CTA Button */
.aura-btn-primary,
.hero__cta,
.button--primary {
  position: relative;
  overflow: hidden;
  transition:
    transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
    box-shadow 0.4s ease !important;
  will-change: transform, box-shadow;
}
.aura-btn-primary::before,
.hero__cta::before,
.button--primary::before {
  content: '';
  position: absolute;
  top: 50%; left: 50%;
  width: 0; height: 0;
  background: rgba(255,255,255,0.2);
  border-radius: 50%;
  transform: translate(-50%, -50%);
  transition: width 0.55s ease, height 0.55s ease, opacity 0.55s ease;
  pointer-events: none;
}
.aura-btn-primary::after,
.hero__cta::after,
.button--primary::after {
  content: '';
  position: absolute;
  top: -50%; left: -75%;
  width: 50%; height: 200%;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.25), transparent);
  transform: skewX(-20deg);
  transition: left 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  pointer-events: none;
}
.aura-btn-primary:hover,
.hero__cta:hover,
.button--primary:hover {
  transform: scale(1.04) translateY(-2px) !important;
  box-shadow: 0 12px 40px rgba(100, 80, 50, 0.25), 0 0 0 1px rgba(180,155,120,0.2) !important;
}
.aura-btn-primary:hover::after,
.hero__cta:hover::after,
.button--primary:hover::after {
  left: 125%;
}
.aura-btn-primary:active,
.button--primary:active {
  transform: scale(0.97) !important;
}

/* Ripple */
.aura-ripple {
  position: absolute;
  border-radius: 50%;
  background: rgba(255,255,255,0.35);
  transform: scale(0);
  animation: aura-ripple-anim 0.6s linear;
  pointer-events: none;
}
@keyframes aura-ripple-anim {
  to { transform: scale(4); opacity: 0; }
}

/* ─── Middle Banner ──────────────────────────────────────────── */
.aura-mid-banner {
  position: relative;
  overflow: hidden;
  min-height: 520px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: none;
}

.aura-mid-banner__bg {
  position: absolute;
  inset: -10%;
  background-size: cover;
  background-position: center;
  will-change: transform;
  transition: transform 0.1s linear;
}

.aura-mid-banner__overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    135deg,
    rgba(45, 35, 25, 0.52) 0%,
    rgba(45, 35, 25, 0.28) 60%,
    rgba(180, 155, 120, 0.1) 100%
  );
}

.aura-mid-banner__content {
  position: relative;
  z-index: 2;
  text-align: center;
  padding: 4rem 2rem;
  max-width: 720px;
}

.aura-mid-banner__eyebrow {
  display: block;
  font-size: 0.78rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.65);
  margin-bottom: 1.25rem;
  opacity: 0;
  transform: translateY(16px);
  transition: opacity 0.7s ease 0.1s, transform 0.7s ease 0.1s;
}

.aura-mid-banner__title {
  font-size: clamp(2rem, 5vw, 3.6rem);
  color: #fff;
  line-height: 1.18;
  margin-bottom: 1.5rem;
  opacity: 0;
  transform: translateY(22px);
  transition: opacity 0.8s ease 0.25s, transform 0.8s ease 0.25s;
}

.aura-mid-banner__subtitle {
  font-size: clamp(0.95rem, 1.8vw, 1.1rem);
  color: rgba(255,255,255,0.75);
  line-height: 1.7;
  margin-bottom: 2.5rem;
  opacity: 0;
  transform: translateY(18px);
  transition: opacity 0.8s ease 0.4s, transform 0.8s ease 0.4s;
}

.aura-mid-banner__cta {
  opacity: 0;
  transform: translateY(14px) scale(0.97);
  transition: opacity 0.7s ease 0.55s, transform 0.7s ease 0.55s;
  display: inline-block;
  padding: 1rem 2.5rem;
  border: 1.5px solid rgba(255,255,255,0.7);
  color: #fff;
  text-decoration: none;
  letter-spacing: 0.12em;
  font-size: 0.85rem;
  text-transform: uppercase;
  position: relative;
  overflow: hidden;
  transition:
    opacity 0.7s ease 0.55s,
    transform 0.7s ease 0.55s,
    border-color 0.35s ease,
    background 0.35s ease,
    color 0.35s ease;
}
.aura-mid-banner__cta::after {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(255,255,255,0.12);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}
.aura-mid-banner__cta:hover::after { transform: scaleX(1); }
.aura-mid-banner__cta:hover {
  border-color: #fff;
  background: transparent;
}

.aura-mid-banner--visible .aura-mid-banner__eyebrow,
.aura-mid-banner--visible .aura-mid-banner__title,
.aura-mid-banner--visible .aura-mid-banner__subtitle,
.aura-mid-banner--visible .aura-mid-banner__cta {
  opacity: 1;
  transform: none;
}
.aura-mid-banner--visible .aura-mid-banner__cta {
  transform: scale(1);
}

/* Floating particles */
.aura-particle {
  position: absolute;
  border-radius: 50%;
  background: rgba(255, 248, 235, 0.18);
  pointer-events: none;
  animation: aura-float var(--duration, 8s) ease-in-out infinite alternate;
  will-change: transform;
}
@keyframes aura-float {
  from { transform: translateY(0) rotate(0deg); }
  to   { transform: translateY(var(--drift, -24px)) rotate(var(--rot, 12deg)); }
}

/* ─── Product Cards ──────────────────────────────────────────── */
.card-wrapper,
.product-card-wrapper,
.grid__item {
  transform-style: preserve-3d;
  perspective: 1000px;
}

.card,
.product-card,
.card--product {
  transition:
    transform 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94),
    box-shadow 0.45s ease;
  will-change: transform, box-shadow;
  transform-style: preserve-3d;
}

.card:hover,
.card--product:hover {
  box-shadow:
    0 20px 60px rgba(100, 80, 50, 0.18),
    0 8px 24px rgba(100, 80, 50, 0.1);
}

/* Product image ken-burns */
.card__media,
.card-media,
.product-card__image-wrapper {
  overflow: hidden;
}

.card__media img,
.card-media img,
.product-card__image-wrapper img,
.card__media .media img {
  transition: transform 0.7s cubic-bezier(0.25, 0.46, 0.45, 0.94) !important;
  will-change: transform;
  transform-origin: center center;
}

.card:hover .card__media img,
.card:hover .card-media img,
.card--product:hover .card__media img,
.card--product:hover .card__media .media img {
  transform: scale(1.085) !important;
}

/* Product card text lift */
.card__content,
.card-information,
.product-card__info {
  transition: transform 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}
.card:hover .card__content,
.card:hover .card-information,
.card--product:hover .card__content {
  transform: translateY(-4px);
}

.card__heading a,
.card-information__heading a {
  transition: color 0.3s ease;
}
.card:hover .card__heading a,
.card:hover .card-information__heading a {
  color: rgba(120, 95, 65, 1);
}

/* Quick add button reveal */
.quick-add,
.card__footer .button {
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 0.35s ease, transform 0.35s ease !important;
}
.card:hover .quick-add,
.card:hover .card__footer .button {
  opacity: 1;
  transform: translateY(0) !important;
}

/* ─── Scroll Reveal (base states) ───────────────────────────── */
.aura-reveal {
  opacity: 0;
  transform: translateY(36px);
  transition: opacity 0.75s cubic-bezier(0.25, 0.46, 0.45, 0.94), transform 0.75s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  will-change: opacity, transform;
}
.aura-reveal--visible {
  opacity: 1;
  transform: translateY(0);
}

.aura-reveal--scale {
  transform: translateY(24px) scale(0.97);
}
.aura-reveal--scale.aura-reveal--visible {
  transform: translateY(0) scale(1);
}

.aura-reveal--left  { transform: translateX(-40px) translateY(0); }
.aura-reveal--right { transform: translateX(40px) translateY(0); }
.aura-reveal--left.aura-reveal--visible,
.aura-reveal--right.aura-reveal--visible { transform: translateX(0); }

/* Stagger delays */
.aura-stagger > *:nth-child(1) { transition-delay: 0s; }
.aura-stagger > *:nth-child(2) { transition-delay: 0.1s; }
.aura-stagger > *:nth-child(3) { transition-delay: 0.2s; }
.aura-stagger > *:nth-child(4) { transition-delay: 0.3s; }
.aura-stagger > *:nth-child(5) { transition-delay: 0.4s; }
.aura-stagger > *:nth-child(6) { transition-delay: 0.5s; }
.aura-stagger > *:nth-child(n+7) { transition-delay: 0.6s; }

/* ─── Breathing / Organic pulse ─────────────────────────────── */
.aura-breathe {
  animation: aura-breathe 5s ease-in-out infinite;
}
@keyframes aura-breathe {
  0%, 100% { transform: scale(1) rotate(0deg); }
  33%       { transform: scale(1.012) rotate(0.4deg); }
  66%       { transform: scale(0.991) rotate(-0.3deg); }
}

.aura-pulse-border {
  animation: aura-pulse-border 3.5s ease-in-out infinite;
}
@keyframes aura-pulse-border {
  0%, 100% { box-shadow: 0 0 0 0 rgba(180, 155, 120, 0); }
  50%       { box-shadow: 0 0 0 8px rgba(180, 155, 120, 0); }
}

/* ─── Footer ─────────────────────────────────────────────────── */
.footer,
.site-footer {
  overflow: hidden;
}

.footer__content-top,
.footer__column,
.site-footer__column {
  transition: transform 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94), opacity 0.45s ease;
  will-change: transform, opacity;
}

.footer a,
.site-footer a {
  position: relative;
  transition: color 0.3s ease, letter-spacing 0.3s ease;
  display: inline-block;
}
.footer a::after,
.site-footer a::after {
  content: '';
  position: absolute;
  bottom: -1px; left: 0;
  width: 0; height: 1px;
  background: currentColor;
  opacity: 0.6;
  transition: width 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}
.footer a:hover::after,
.site-footer a:hover::after { width: 100%; }
.footer a:hover,
.site-footer a:hover { letter-spacing: 0.015em; }

.footer__newsletter,
.footer-block__newsletter { overflow: visible; }

/* Social icons footer */
.footer .list-social__link,
.site-footer .list-social__link {
  transition:
    transform 0.35s cubic-bezier(0.34, 1.56, 0.64, 1),
    filter 0.35s ease !important;
  display: inline-flex;
}
.footer .list-social__link:hover,
.site-footer .list-social__link:hover {
  transform: translateY(-4px) scale(1.15) !important;
  filter: drop-shadow(0 4px 12px rgba(180,155,120,0.5)) !important;
}

/* ─── Section headings global ────────────────────────────────── */
.title,
.section-header h2,
.collection__title {
  transition: letter-spacing 0.4s ease;
}

/* ─── Media queries — desabilitar animações caras no mobile ─── */
@media (max-width: 749px) {
  * { cursor: auto !important; }
  .aura-cursor, .aura-cursor-ring { display: none !important; }

  .card:hover { transform: none !important; box-shadow: none !important; }
  .card:hover .card__media img { transform: none !important; }
  .card:hover .card__content { transform: none !important; }
  .card:hover .quick-add,
  .card:hover .card__footer .button {
    opacity: 1 !important;
    transform: none !important;
  }
  .aura-breathe { animation: none !important; }
  .aura-particle { display: none !important; }
  .hero-parallax-bg { transform: none !important; }
}

/* ─── Reduced motion ─────────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
  .aura-cursor, .aura-cursor-ring { display: none; }
}

/* ════════════════════════════════════════════════════════════════
   Aura Decore — Premium Motion & Interactivity Engine
   THEO + LUNA · Aura Decore 2026
   Dependências: GSAP 3 + ScrollTrigger (via CDN, injetado abaixo)
   Colar em: Online Store → Themes → Edit code → assets/aura-animations.js
   ════════════════════════════════════════════════════════════════ */

(function () {
  'use strict';

  /* ── Aguarda GSAP estar disponível ─────────────────────────── */
  function waitForGSAP(cb, tries = 0) {
    if (typeof gsap !== 'undefined' && typeof ScrollTrigger !== 'undefined') {
      gsap.registerPlugin(ScrollTrigger);
      cb();
    } else if (tries < 60) {
      setTimeout(() => waitForGSAP(cb, tries + 1), 100);
    }
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 1 — Custom Cursor
  ════════════════════════════════════════════════════════════ */
  function initCursor() {
    if (window.matchMedia('(max-width: 749px)').matches) return;
    if (window.matchMedia('(pointer: coarse)').matches) return;

    const dot  = document.createElement('div');
    const ring = document.createElement('div');
    dot.className  = 'aura-cursor';
    ring.className = 'aura-cursor-ring';
    document.body.appendChild(dot);
    document.body.appendChild(ring);

    let mx = -100, my = -100;
    let rx = -100, ry = -100;

    document.addEventListener('mousemove', (e) => {
      mx = e.clientX; my = e.clientY;
      gsap.set(dot, { x: mx, y: my });
    });

    // Ring follows with lerp
    gsap.ticker.add(() => {
      rx += (mx - rx) * 0.12;
      ry += (my - ry) * 0.12;
      gsap.set(ring, { x: rx, y: ry });
    });

    // Hover states
    document.querySelectorAll('a, button, [role="button"], .card, input, textarea, select, label').forEach(el => {
      el.addEventListener('mouseenter', () => {
        dot.classList.add('aura-cursor--hover');
        ring.classList.add('aura-cursor-ring--hover');
      });
      el.addEventListener('mouseleave', () => {
        dot.classList.remove('aura-cursor--hover');
        ring.classList.remove('aura-cursor-ring--hover');
      });
    });

    document.addEventListener('mousedown', () => dot.classList.add('aura-cursor--click'));
    document.addEventListener('mouseup',   () => dot.classList.remove('aura-cursor--click'));
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 2 — Header Scroll
  ════════════════════════════════════════════════════════════ */
  function initHeader() {
    const header = document.querySelector(
      '.header-wrapper, .site-header, header[role="banner"]'
    );
    if (!header) return;

    let lastScroll = 0;
    const THRESHOLD = 80;

    window.addEventListener('scroll', () => {
      const current = window.scrollY;

      if (current > THRESHOLD) {
        header.classList.add('header--scrolled');
      } else {
        header.classList.remove('header--scrolled');
      }

      lastScroll = current;
    }, { passive: true });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 3 — Hero Parallax + Mouse Follow
  ════════════════════════════════════════════════════════════ */
  function initHeroParallax() {
    const hero = document.querySelector(
      '.banner, .hero, [data-section-type="image-banner"], .slideshow, section.image-banner'
    );
    if (!hero) return;

    hero.classList.add('hero-parallax-wrapper');
    const bg = hero.querySelector('img, .banner__media, .media, video');
    if (bg) bg.classList.add('hero-parallax-bg');

    // Scroll parallax
    gsap.to(bg, {
      yPercent: 28,
      ease: 'none',
      scrollTrigger: {
        trigger: hero,
        start: 'top top',
        end: 'bottom top',
        scrub: 1.2,
      },
    });

    // Mouse parallax (follow)
    let targetX = 0, targetY = 0;
    let currentX = 0, currentY = 0;
    const STRENGTH = 14;

    document.addEventListener('mousemove', (e) => {
      targetX = (e.clientX / window.innerWidth  - 0.5) * STRENGTH;
      targetY = (e.clientY / window.innerHeight - 0.5) * STRENGTH;
    });

    gsap.ticker.add(() => {
      currentX += (targetX - currentX) * 0.06;
      currentY += (targetY - currentY) * 0.06;
      if (bg) gsap.set(bg, { x: currentX, y: currentY });

      // Decorative layers at different depths
      document.querySelectorAll('.banner__content .field, .banner__box, .hero__text-group').forEach((el, i) => {
        const depth = (i % 3 + 1) * 0.4;
        gsap.set(el, { x: currentX * depth, y: currentY * depth * 0.5 });
      });
    });

    // Text stagger entrance
    const textEls = hero.querySelectorAll(
      '.banner__heading, .banner__subheading, .hero__title, .hero__description, .banner__content a, .banner__buttons'
    );
    textEls.forEach(el => el.classList.add('hero-stagger-item'));

    gsap.to(textEls, {
      opacity: 1,
      y: 0,
      duration: 1,
      stagger: 0.18,
      ease: 'power3.out',
      delay: 0.3,
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 4 — Middle Banner Dinâmico
     Insere automaticamente entre 2ª e 3ª seção da homepage
  ════════════════════════════════════════════════════════════ */
  function initMidBanner() {
    // Não inserir se já existe
    if (document.querySelector('.aura-mid-banner')) return;

    const sections = document.querySelectorAll('.shopify-section, section[class*="section"]');
    if (sections.length < 3) return;

    // Imagem de fundo — usa a primeira imagem grande encontrada na página como fallback
    const heroImg = document.querySelector(
      '.banner img, .hero img, .slideshow img'
    );
    const bgUrl = heroImg
      ? heroImg.src.replace(/(\.[^.]+)$/, '_2048x$1').replace(/&width=\d+/, '&width=2048')
      : '';

    const banner = document.createElement('div');
    banner.className = 'shopify-section aura-mid-banner';
    banner.setAttribute('data-aura-mid', 'true');
    if (bgUrl) banner.style.setProperty('--mid-bg', `url("${bgUrl}")`);

    banner.innerHTML = `
      <div class="aura-mid-banner__bg" style="background-image: var(--mid-bg, linear-gradient(135deg, #2d1f14 0%, #4a3525 40%, #2d2318 100%));"></div>
      <div class="aura-mid-banner__overlay"></div>

      <div class="aura-mid-banner__content">
        <span class="aura-mid-banner__eyebrow">Aura Decore — Japandi Living</span>
        <h2 class="aura-mid-banner__title">Um espaço que respira<br>intenção e beleza</h2>
        <p class="aura-mid-banner__subtitle">
          Cada peça da nossa coleção foi escolhida para trazer equilíbrio,<br>
          calma e sofisticação ao seu lar.
        </p>
        <a href="/collections/all" class="aura-mid-banner__cta">Explorar coleção</a>
      </div>

      <div class="aura-particle" style="width:180px;height:180px;top:10%;left:5%;--duration:9s;--drift:-30px;--rot:15deg;opacity:0.06;"></div>
      <div class="aura-particle" style="width:80px;height:80px;top:70%;right:8%;--duration:7s;--drift:-20px;--rot:-10deg;opacity:0.1;animation-delay:-3s;"></div>
      <div class="aura-particle" style="width:260px;height:260px;bottom:-60px;right:-40px;--duration:12s;--drift:-15px;--rot:8deg;opacity:0.04;"></div>
    `;

    // Insere após a 2ª seção
    sections[1].insertAdjacentElement('afterend', banner);

    // ScrollTrigger reveal
    ScrollTrigger.create({
      trigger: banner,
      start: 'top 72%',
      onEnter: () => banner.classList.add('aura-mid-banner--visible'),
    });

    // Parallax scroll no bg interno
    const midBg = banner.querySelector('.aura-mid-banner__bg');
    gsap.to(midBg, {
      yPercent: 18,
      ease: 'none',
      scrollTrigger: {
        trigger: banner,
        start: 'top bottom',
        end: 'bottom top',
        scrub: 1.5,
      },
    });

    // Mouse follow dentro do banner
    let tmx = 0, tmy = 0, cmx = 0, cmy = 0;
    banner.addEventListener('mousemove', (e) => {
      const rect = banner.getBoundingClientRect();
      tmx = (e.clientX - rect.left) / rect.width  - 0.5;
      tmy = (e.clientY - rect.top)  / rect.height - 0.5;
    });
    banner.addEventListener('mouseleave', () => { tmx = 0; tmy = 0; });

    gsap.ticker.add(() => {
      cmx += (tmx - cmx) * 0.07;
      cmy += (tmy - cmy) * 0.07;
      gsap.set(midBg, { x: cmx * 20, y: cmy * 12 });
    });

    // Ripple no CTA do banner
    const cta = banner.querySelector('.aura-mid-banner__cta');
    if (cta) {
      cta.addEventListener('click', (e) => {
        const ripple = document.createElement('span');
        ripple.className = 'aura-ripple';
        const rect = cta.getBoundingClientRect();
        const size = Math.max(rect.width, rect.height) * 2;
        ripple.style.cssText = `width:${size}px;height:${size}px;left:${e.clientX-rect.left-size/2}px;top:${e.clientY-rect.top-size/2}px`;
        cta.style.overflow = 'hidden';
        cta.style.position = 'relative';
        cta.appendChild(ripple);
        ripple.addEventListener('animationend', () => ripple.remove());
      });
    }
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 5 — Scroll Reveal Global (IntersectionObserver)
  ════════════════════════════════════════════════════════════ */
  function initScrollReveal() {
    const SELECTORS = [
      '.collection-list__item',
      '.product-grid > *',
      '.grid--2-col > *',
      '.grid--3-col > *',
      '.grid--4-col > *',
      '.featured-collection .card-wrapper',
      '.section-header',
      '.rich-text',
      '.image-with-text__content',
      '.image-with-text__media',
      '.multicolumn-list__item',
      '.blog-articles article',
      '.footer__column',
      '.footer__content-bottom',
      '.testimonials-slider__slide',
    ];

    const candidates = document.querySelectorAll(SELECTORS.join(', '));
    const seen = new WeakSet();

    candidates.forEach((el, i) => {
      if (seen.has(el)) return;
      seen.add(el);
      el.classList.add('aura-reveal');
      if (i % 3 === 1) el.classList.add('aura-reveal--scale');
    });

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('aura-reveal--visible');
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.12, rootMargin: '0px 0px -40px 0px' }
    );

    document.querySelectorAll('.aura-reveal').forEach(el => observer.observe(el));
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 6 — Product Card 3D Hover (GSAP)
  ════════════════════════════════════════════════════════════ */
  function initCardHover() {
    if (window.matchMedia('(max-width: 749px)').matches) return;

    const cards = document.querySelectorAll('.card, .card--product, .product-card');

    cards.forEach(card => {
      const TILT_MAX = 8;

      card.addEventListener('mousemove', (e) => {
        const rect = card.getBoundingClientRect();
        const cx = rect.left + rect.width  / 2;
        const cy = rect.top  + rect.height / 2;
        const dx = (e.clientX - cx) / (rect.width  / 2);
        const dy = (e.clientY - cy) / (rect.height / 2);
        const rotY =  dx * TILT_MAX;
        const rotX = -dy * TILT_MAX;

        gsap.to(card, {
          rotateX: rotX,
          rotateY: rotY,
          transformPerspective: 900,
          ease: 'power2.out',
          duration: 0.45,
        });
      });

      card.addEventListener('mouseleave', () => {
        gsap.to(card, {
          rotateX: 0, rotateY: 0,
          ease: 'elastic.out(1, 0.5)',
          duration: 0.8,
        });
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 7 — Button Ripple
  ════════════════════════════════════════════════════════════ */
  function initButtonRipple() {
    document.querySelectorAll(
      'button.button, a.button, .button--primary, .button--secondary, .cart__checkout-button, form[action="/cart"] button'
    ).forEach(btn => {
      btn.style.overflow = 'hidden';
      btn.style.position = 'relative';
      btn.addEventListener('click', (e) => {
        const ripple = document.createElement('span');
        ripple.className = 'aura-ripple';
        const rect = btn.getBoundingClientRect();
        const size = Math.max(rect.width, rect.height) * 2.5;
        ripple.style.cssText = `
          width: ${size}px; height: ${size}px;
          left: ${e.clientX - rect.left - size / 2}px;
          top:  ${e.clientY - rect.top  - size / 2}px;
        `;
        btn.appendChild(ripple);
        ripple.addEventListener('animationend', () => ripple.remove());
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 8 — Seções com GSAP ScrollTrigger
  ════════════════════════════════════════════════════════════ */
  function initSectionAnimations() {
    // Section headings
    document.querySelectorAll('.section-header, .collection__title, .title').forEach(el => {
      gsap.from(el, {
        opacity: 0,
        y: 30,
        duration: 0.9,
        ease: 'power3.out',
        scrollTrigger: {
          trigger: el,
          start: 'top 85%',
          toggleActions: 'play none none none',
        },
      });
    });

    // Featured collection grid stagger
    document.querySelectorAll('.featured-collection, .collection-list, .product-recommendations').forEach(section => {
      const items = section.querySelectorAll('.card-wrapper, .collection-list__item');
      if (!items.length) return;
      // Remove IntersectionObserver reveal class para não conflitar
      items.forEach(el => el.classList.remove('aura-reveal'));

      gsap.from(items, {
        opacity: 0,
        y: 40,
        scale: 0.96,
        duration: 0.75,
        stagger: 0.1,
        ease: 'power3.out',
        scrollTrigger: {
          trigger: section,
          start: 'top 78%',
          toggleActions: 'play none none none',
        },
      });
    });

    // Image-with-text split entrance
    document.querySelectorAll('.image-with-text').forEach(section => {
      const media   = section.querySelector('.image-with-text__media');
      const content = section.querySelector('.image-with-text__content');

      if (media) gsap.from(media, {
        opacity: 0, x: -50, duration: 1, ease: 'power3.out',
        scrollTrigger: { trigger: section, start: 'top 80%', toggleActions: 'play none none none' },
      });
      if (content) gsap.from(content, {
        opacity: 0, x: 50, duration: 1, ease: 'power3.out',
        scrollTrigger: { trigger: section, start: 'top 80%', toggleActions: 'play none none none' },
      });
    });

    // Rich text / multicolumn
    document.querySelectorAll('.rich-text__blocks > *, .multicolumn-list__item').forEach((el, i) => {
      el.classList.remove('aura-reveal');
      gsap.from(el, {
        opacity: 0, y: 32,
        duration: 0.75,
        delay: i * 0.09,
        ease: 'power3.out',
        scrollTrigger: {
          trigger: el,
          start: 'top 85%',
          toggleActions: 'play none none none',
        },
      });
    });
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 9 — Footer reveal GSAP
  ════════════════════════════════════════════════════════════ */
  function initFooter() {
    const footer = document.querySelector('.footer, .site-footer');
    if (!footer) return;

    const columns = footer.querySelectorAll('.footer__column, .footer-block, .site-footer__column');
    columns.forEach(col => col.classList.remove('aura-reveal'));

    gsap.from(columns, {
      opacity: 0,
      y: 28,
      stagger: 0.12,
      duration: 0.8,
      ease: 'power3.out',
      scrollTrigger: {
        trigger: footer,
        start: 'top 88%',
        toggleActions: 'play none none none',
      },
    });

    const bottom = footer.querySelector('.footer__content-bottom');
    if (bottom) {
      bottom.classList.remove('aura-reveal');
      gsap.from(bottom, {
        opacity: 0, y: 18,
        duration: 0.7, ease: 'power3.out',
        scrollTrigger: { trigger: bottom, start: 'top 95%', toggleActions: 'play none none none' },
      });
    }
  }

  /* ════════════════════════════════════════════════════════════
     MÓDULO 10 — Breathing em elementos decorativos
  ════════════════════════════════════════════════════════════ */
  function initBreathe() {
    // Ícones de confiança, badges, selos
    document.querySelectorAll(
      '.trust-badges img, .icon-with-text__icon, .newsletter__icon, .announcement-bar__message'
    ).forEach(el => {
      el.classList.add('aura-breathe');
    });
  }

  /* ════════════════════════════════════════════════════════════
     BOOT — inicializa tudo
  ════════════════════════════════════════════════════════════ */
  function boot() {
    initCursor();
    initHeader();
    initHeroParallax();
    initScrollReveal();
    initCardHover();
    initButtonRipple();
    initBreathe();

    // GSAP-dependent
    waitForGSAP(() => {
      initMidBanner();
      initSectionAnimations();
      initFooter();

      // ScrollTrigger refresh após tudo montado
      setTimeout(() => ScrollTrigger.refresh(), 500);
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }

})();
